import React from "react"
import styled from "styled-components"
import { Link, graphql } from "gatsby"

// import Bio from "../components/bio"
import Layout from "../components/layout"
import SEO from "../components/seo"
import Reactions from "../components/reactions"

const PostHeader = styled.div`
  background-color: #3a91ee;
  color: #fff;
  text-align: center;
  padding: 100px 50px;
  line-height: 1.3;
  word-break: keep-all;
`
const Title = styled.div`
  font-weight: 700;
  font-size: 30px;
`
const SubTitle = styled.div`
  margin-top: 5px;
  font-size: 20px;
  font-weight: 400;
`
const Date = styled.div`
  font-size: 14px;
  font-weight: 400;
  margin-bottom: 20px;
  opacity: 0.7;
`
const PostContent = styled.div`
  width: 100%;
  margin: 0 auto;
  max-width: 840px;
  padding: 24px 32px;
  background-color: #fff;
`
const Category = styled.div`
  font-size: 14px;
  font-weight: 400;
  margin-top: 20px;
`
const CategoryLink = styled.a`
  font-weight: 700;
  margin-left: 6px;
`

const PrevNext = styled.div`
  width: 100%;
  max-width: 840px;
  margin: 20px auto;
  padding: 32px;
  background-color: #fff;
`

class BlogPostTemplate extends React.Component {
  render() {
    const post = this.props.data.markdownRemark
    const siteTitle = this.props.data.site.siteMetadata.title
    const { previous, next } = this.props.pageContext

    return (
      <Layout location={this.props.location} title={siteTitle}>
        <SEO
          title={post.frontmatter.title}
          description={post.frontmatter.description || post.excerpt}
        />
        <PostHeader>
          <Date>{post.frontmatter.date}</Date>
          <Title>{post.frontmatter.title}</Title>
          {post.frontmatter.subtitle && (
            <SubTitle>{post.frontmatter.subtitle}</SubTitle>
          )}
          {post.frontmatter.category && (
            <Category>
              in
              {post.frontmatter.category.map((category, index) => (
                <CategoryLink href={`/category/${category}`} key={category}>
                  {category}
                  {post.frontmatter.category.length - 1 !== index && ","}
                </CategoryLink>
              ))}
            </Category>
          )}
        </PostHeader>
        <PostContent>
          <div
            className="md-content"
            dangerouslySetInnerHTML={{ __html: post.html }}
          />
        </PostContent>
        <Reactions slug={post.fields.slug} />

        <PrevNext>
          <ul
            style={{
              display: `flex`,
              flexWrap: `wrap`,
              justifyContent: `space-between`,
              listStyle: `none`,
              padding: 0,
            }}
          >
            <li>
              {previous && (
                <Link to={previous.fields.slug} rel="prev">
                  ← {previous.frontmatter.title}
                </Link>
              )}
            </li>
            <li>
              {next && (
                <Link to={next.fields.slug} rel="next">
                  {next.frontmatter.title} →
                </Link>
              )}
            </li>
          </ul>
        </PrevNext>
      </Layout>
    )
  }
}

export default BlogPostTemplate

export const pageQuery = graphql`
  query BlogPostBySlug($slug: String!) {
    site {
      siteMetadata {
        title
        author
      }
    }
    markdownRemark(fields: { slug: { eq: $slug } }) {
      id
      excerpt(pruneLength: 160)
      html
      fields {
        slug
      }
      frontmatter {
        title
        subtitle
        date(formatString: "YYYY-MM-DD")
        description
        category
      }
    }
  }
`
