import React from "react"
import styled from "styled-components"
import axios from "axios"

const Wrap = styled.div`
  max-width: 840px;
  margin: 0 auto;
  display: flex;
  justify-content: space-between;
  background-color: #fff;
  padding: 3%;
`
const Item = styled.div`
  position: relative;
  flex: 1;
  width: 15%;
  text-align: center;
  background-color: #eee;
  padding: 36px 2% 16px 2%;
  margin: 1%;
  border-radius: 16px;
  user-select: none;
`
const Count = styled.div`
  position: absolute;
  bottom: 56px;
  left: 0;
  width: 100%;
  text-align: center;
  margin: 0;
  padding: 0;
  transition: all 100ms;
  font-size: ${props => (props.size ? props.size : "14px")};
  font-weight: ${props => (props.rotate ? "bold" : "normal")};
  color: ${props => (props.rotate ? "#3a91ee" : "inherit")};
  transform: ${props => {
    const list = [`translateY(50%)`]
    if (props.rotate) {
      list.push(`rotate(${props.rotate})`)
    }
    return list.join(" ")
  }};
  zoom: ${props => (props.zoom ? props.zoom : "1")};
`
const Emoji = styled.div`
  font-size: 24px;
`

class Reactions extends React.Component {
  state = {
    keepPressTime: 100,
    keepPressCount: 0,
    keepPressInterval: null,
    keepPressType: "",
    like: 0,
    heart: 0,
    fun: 0,
    merong: 0,
    sad: 0,
    angry: 0,
    zoom: 1,
    rotate: 0,
  }
  async componentDidMount() {
    const { data } = await axios.get(
      `https://us-central1-reaction-buttons.cloudfunctions.net/getReactions?host=${btoa(
        "chichi.space"
      )}&slug=${btoa(encodeURI(this.props.slug))}`
    )
    const like = data.like && data.like.count ? Number(data.like.count) : 0
    const heart = data.heart && data.heart.count ? Number(data.heart.count) : 0
    const fun = data.fun && data.fun.count ? Number(data.fun.count) : 0
    const merong =
      data.merong && data.merong.count ? Number(data.merong.count) : 0
    const sad = data.sad && data.sad.count ? Number(data.sad.count) : 0
    const angry = data.angry && data.angry.count ? Number(data.angry.count) : 0

    this.setState({
      like,
      heart,
      fun,
      merong,
      sad,
      angry,
    })
  }

  createReaction(reaction, count = 0) {
    if (count === 0) {
      return null
    }
    if (count > 50) {
      count = 50
    }
    axios.get(
      `https://us-central1-reaction-buttons.cloudfunctions.net/addReactions?host=${btoa(
        "chichi.space"
      )}&slug=${btoa(
        encodeURI(this.props.slug)
      )}&reaction=${reaction}&count=${count}`
    )
    this.setState({
      keepPressCount: 0,
    })
  }
  handleMouseDown(reaction) {
    const upVote = () => {
      this.setState({
        keepPressCount: this.state.keepPressCount + 1,
        [reaction]: this.state[reaction] + 1,
        zoom: this.getRandomArbitrary(100, 120) / 100,
        rotate: this.getRandomArbitrary(-15, 16) + "deg",
      })
      console.log(this.state.keepPressCount)
    }
    upVote()
    const keepPressInterval = setInterval(upVote, this.state.keepPressTime)
    this.setState({
      keepPressInterval,
      keepPressType: reaction,
    })
    console.log("down", reaction)
  }
  handleMouseUp(reaction) {
    const { keepPressCount } = this.state
    clearInterval(this.state.keepPressInterval)
    this.createReaction(reaction, keepPressCount)
    this.setState({
      keepPressType: "",
    })
    console.log("up", reaction)
  }

  getRandomArbitrary(min, max) {
    return Math.random() * (max - min) + min
  }

  render() {
    const {
      like,
      heart,
      fun,
      merong,
      sad,
      angry,
      keepPressType,
      zoom,
      rotate,
    } = this.state
    return (
      <Wrap>
        <Item
          onMouseDown={() => this.handleMouseDown("like")}
          onMouseUp={() => this.handleMouseUp("like")}
          onMouseLeave={() => this.handleMouseUp("like")}
          onTouchStart={() => this.handleMouseDown("like")}
          onTouchEnd={() => this.handleMouseUp("like")}
          onTouchCancel={() => this.handleMouseUp("like")}
        >
          {keepPressType === "like" ? (
            <Count rotate={rotate} zoom={zoom}>
              {like}
            </Count>
          ) : (
            <Count>{like}</Count>
          )}
          <Emoji>👍</Emoji>
        </Item>
        <Item
          onMouseDown={() => this.handleMouseDown("heart")}
          onMouseUp={() => this.handleMouseUp("heart")}
          onMouseLeave={() => this.handleMouseUp("heart")}
          onTouchStart={() => this.handleMouseDown("heart")}
          onTouchEnd={() => this.handleMouseUp("heart")}
          onTouchCancel={() => this.handleMouseUp("heart")}
        >
          {keepPressType === "heart" ? (
            <Count rotate={rotate} zoom={zoom}>
              {heart}
            </Count>
          ) : (
            <Count>{heart}</Count>
          )}
          <Emoji>❤️</Emoji>
        </Item>
        <Item
          onMouseDown={() => this.handleMouseDown("fun")}
          onMouseUp={() => this.handleMouseUp("fun")}
          onMouseLeave={() => this.handleMouseUp("fun")}
          onTouchStart={() => this.handleMouseDown("fun")}
          onTouchEnd={() => this.handleMouseUp("fun")}
          onTouchCancel={() => this.handleMouseUp("fun")}
        >
          {keepPressType === "fun" ? (
            <Count rotate={rotate} zoom={zoom}>
              {fun}
            </Count>
          ) : (
            <Count>{fun}</Count>
          )}
          <Emoji>😄</Emoji>
        </Item>
        <Item
          onMouseDown={() => this.handleMouseDown("merong")}
          onMouseUp={() => this.handleMouseUp("merong")}
          onMouseLeave={() => this.handleMouseUp("merong")}
          onTouchStart={() => this.handleMouseDown("merong")}
          onTouchEnd={() => this.handleMouseUp("merong")}
          onTouchCancel={() => this.handleMouseUp("merong")}
        >
          {keepPressType === "merong" ? (
            <Count rotate={rotate} zoom={zoom}>
              {merong}
            </Count>
          ) : (
            <Count>{merong}</Count>
          )}
          <Emoji>😝</Emoji>
        </Item>
      </Wrap>
    )
  }
}

export default Reactions
